import express from "express";
import { readFile } from "node:fs/promises";
import path, { join } from "node:path";
import http from "node:http";

export const app = express();
app.use(express.json());

const PORT = Number(process.env.PORT || 8090);
const PUBLIC_HOST = process.env.PUBLIC_HOST || "localhost"; // used to build container URLs
const DOCKER_SOCK = process.env.DOCKER_SOCK || "/var/run/docker.sock";

// Serve static
const publicDir = join(process.cwd(), "public");
app.use(express.static(publicDir));

// Seed tiles
const seedTiles = [
  { url: "https://monitor.starkitconsulting.com", title: "Monitor" },
  { url: "https://weather.starkitconsulting.com", title: "Weather" },
  { url: "https://starkitconsulting.com", title: "Starkit" },
];

async function dockerRequestJson(pathname: string): Promise<any> {
  return new Promise((resolve, reject) => {
    const req = http.request({ socketPath: DOCKER_SOCK, path: pathname, method: "GET" }, (res) => {
      let buf: Buffer[] = [];
      res.on("data", (c) => buf.push(Buffer.isBuffer(c) ? c : Buffer.from(c)));
      res.on("end", () => {
        if ((res.statusCode || 0) >= 300) return reject(new Error(`docker ${pathname} -> ${res.statusCode}`));
        const text = Buffer.concat(buf).toString("utf8");
        try { resolve(JSON.parse(text)); } catch { resolve(text); }
      });
    });
    req.on("error", reject);
    req.end();
  });
}

function uniqueBy<T>(items: T[], key: (t: T) => string): T[] {
  const seen = new Set<string>();
  const out: T[] = [];
  for (const it of items) {
    const k = key(it);
    if (!seen.has(k)) { seen.add(k); out.push(it); }
  }
  return out;
}

app.get("/api/containers", async (_req, res) => {
  try {
    const data = await dockerRequestJson("/containers/json?all=0");
    res.json(data);
  } catch (e: any) {
    res.status(500).json({ error: String(e?.message || e) });
  }
});

app.get("/api/tiles", async (_req, res) => {
  try {
    const conts = await dockerRequestJson("/containers/json?all=0");
    const dyn: { url: string; title: string }[] = [];
    for (const c of conts) {
      const ports = c.Ports as Array<{ PrivatePort?: number; PublicPort?: number; Type?: string }>;
      const first = (ports || []).find((p) => p.Type === "tcp" && p.PublicPort);
      if (first && first.PublicPort) {
        const name = (c.Names?.[0] as string || c.Id).replace(/\//g, "");
        const url = `http://${PUBLIC_HOST}:${first.PublicPort}`;
        dyn.push({ url, title: name });
      }
    }
    const merged = uniqueBy([...seedTiles, ...dyn], (t) => t.url);
    res.json(merged);
  } catch (e: any) {
    res.status(200).json(seedTiles);
  }
});

app.get("/health", (_req, res) => res.json({ ok: true }));

if (import.meta.url === `file://${process.argv[1]}`) {
  app.listen(PORT, () => {
    console.log(`portal listening on :${PORT}`);
  });
}

/* Colors and base */
:root{
  --bg: #0f0f0f;
  --surface: #1a1a2e;
  --surface2: #16213e;
  --accent: #4fc3f7; /* or #00e5ff */
  --text: #e8eaf6;
  --text2: #9e9e9e;
  --border: rgba(255,255,255,0.08);
}
*{box-sizing:border-box}
html,body{height:100%}
body{margin:0;background:var(--bg);color:var(--text);font-family:'Inter',system-ui,Arial,sans-serif;}

/* Header */
.header{position:fixed;top:0;left:0;right:0;height:64px;display:flex;align-items:center;justify-content:space-between;padding:0 20px;background:linear-gradient(180deg, rgba(0,0,0,0.6), rgba(0,0,0,0));z-index:10}
.brand{font-weight:800;letter-spacing:1px}
.hamburger{width:40px;height:40px;border-radius:20px;border:1px solid var(--border);background:transparent;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:4px;cursor:pointer}
.hamburger span{display:block;width:18px;height:2px;background:var(--text)}

/* Hero */
.main{padding-top:80px}
.hero{display:flex;flex-direction:column;align-items:center;gap:10px;margin:40px 0}
.title{font-family:'Bebas Neue','Inter',sans-serif;letter-spacing:2px;text-align:center;line-height:0.9;margin:0;font-size:68px}
.subtitle{color:var(--text2);margin:8px 0 0}

/* Slider */
.slider-section{position:relative;max-width:100vw;overflow:hidden;padding:20px 0}
.slider{display:flex;gap:16px;overflow:hidden;padding:10px 40px;cursor:grab}
.tile{position:relative;flex:0 0 400px;height:500px;border-radius:16px;border:1px solid var(--border);background:linear-gradient(180deg,var(--surface),var(--surface2));box-shadow:0 10px 30px rgba(0,0,0,0.4);overflow:hidden;transform:translateZ(0);transition:transform .2s ease}
.tile:hover{transform:scale(1.02)}
.tile iframe{width:100%;height:100%;border:0;border-radius:16px;filter:contrast(1.02) saturate(0.95)}
.tile .placeholder{position:absolute;inset:0;display:flex;flex-direction:column;align-items:center;justify-content:center;gap:10px;color:var(--text2);padding:16px;text-align:center}
.tile .open-btn{padding:8px 12px;border-radius:999px;border:1px solid var(--border);background:transparent;color:var(--text);cursor:pointer}
.drag-pill{position:absolute;right:20px;top:50%;transform:translateY(-50%);padding:6px 12px;border-radius:999px;border:1px solid var(--border);background:#121212;color:var(--text2);font-size:12px;letter-spacing:2px}

/* Overlay tabs */
.overlay{position:fixed;inset:0;background:var(--bg);display:flex;flex-direction:column;z-index:100}
.hidden{display:none}
.tabbar{height:48px;display:flex;align-items:center;gap:8px;padding:8px 10px;border-bottom:1px solid var(--border);background:#0f0f12}
.home-btn{border:1px solid var(--border);background:transparent;color:var(--text);border-radius:8px;padding:6px 10px;cursor:pointer}
.tabs{display:flex;gap:8px;overflow:auto}
.tab{display:flex;align-items:center;gap:8px;padding:6px 10px;border-radius:8px;background:#16181d;border:1px solid var(--border);color:var(--text2)}
.tab.active{background:#1f2430;color:var(--text)}
.tab img{width:16px;height:16px}
.tab .close{border:0;background:transparent;color:var(--text2);cursor:pointer}
.tabcontent{flex:1;position:relative}
.tabcontent iframe{position:absolute;inset:0;width:100%;height:100%;border:0}

/* Responsive */
@media (max-width: 900px){
  .title{font-size:48px}
  .slider{padding:10px 20px}
  .tile{flex:0 0 85vw;height:60vh}
}

const slider = document.getElementById('slider');
const overlay = document.getElementById('overlay');
const tabsEl = document.getElementById('tabs');
const tabcontent = document.getElementById('tabcontent');
const homeBtn = document.getElementById('homeBtn');

let tiles = [];
let isDown = false; let startX = 0; let scrollLeft = 0; let offsetX = 0;

async function loadTiles(){
  try{
    const r = await fetch('/api/tiles');
    tiles = await r.json();
  }catch(e){
    tiles = [
      { url: 'https://monitor.starkitconsulting.com', title: 'Monitor' },
      { url: 'https://weather.starkitconsulting.com', title: 'Weather' },
      { url: 'https://starkitconsulting.com', title: 'Starkit' },
    ];
  }
  renderTiles();
}

function favicon(url){
  try{
    const u = new URL(url);
    return `https://www.google.com/s2/favicons?sz=64&domain=${u.hostname}`;
  }catch{ return '/favicon.ico'; }
}

function domain(url){
  try{ return new URL(url).hostname; }catch{ return url; }
}

function createTile(t){
  const card = document.createElement('div');
  card.className = 'tile';

  const iframe = document.createElement('iframe');
  iframe.sandbox = 'allow-scripts allow-same-origin';
  iframe.referrerPolicy = 'no-referrer';
  iframe.src = t.url;

  const placeholder = document.createElement('div');
  placeholder.className = 'placeholder';
  const img = document.createElement('img');
  img.src = favicon(t.url); img.width=32; img.height=32; img.alt='';
  const title = document.createElement('div');
  title.textContent = t.title || domain(t.url);
  const open = document.createElement('button');
  open.className='open-btn'; open.textContent='Open';
  open.addEventListener('click', (e)=>{ e.stopPropagation(); openTab(t.url); });
  placeholder.append(img,title,open);

  let loaded = false;
  iframe.addEventListener('load', ()=>{ loaded = true; placeholder.style.display='none'; });
  setTimeout(()=>{ if(!loaded) placeholder.style.display='flex'; }, 1500);

  card.append(iframe, placeholder);
  card.addEventListener('click', ()=> openTab(t.url));
  return card;
}

function renderTiles(){
  slider.innerHTML = '';
  tiles.forEach(t => slider.appendChild(createTile(t)));
}

// drag to scroll
let startPos = 0; let currentX = 0; let base = 0; let isDragging=false;
slider.addEventListener('mousedown', (e)=>{ isDragging=true; slider.style.cursor='grabbing'; startPos=e.clientX; base=slider.scrollLeft; });
slider.addEventListener('mouseleave', ()=>{ isDragging=false; slider.style.cursor='grab'; });
slider.addEventListener('mouseup', ()=>{ isDragging=false; slider.style.cursor='grab'; });
slider.addEventListener('mousemove', (e)=>{ if(!isDragging) return; e.preventDefault(); const dx=e.clientX-startPos; slider.scrollLeft=base-dx; });
// touch
slider.addEventListener('touchstart', (e)=>{ isDragging=true; startPos=e.touches[0].clientX; base=slider.scrollLeft; }, {passive:true});
slider.addEventListener('touchend', ()=>{ isDragging=false; }, {passive:true});
slider.addEventListener('touchmove', (e)=>{ if(!isDragging) return; const dx=e.touches[0].clientX-startPos; slider.scrollLeft=base-dx; }, {passive:true});

// tabs overlay
const tabs = [];
function openTab(url){
  overlay.classList.remove('hidden');
  const existing = tabs.find(t => t.url===url);
  if(existing){ setActive(existing.id); return; }
  const id = Math.random().toString(36).slice(2);
  const tab = { id, url };
  tabs.push(tab);
  renderTabs();
  setActive(id);
}

function setActive(id){
  tabs.forEach(t => t.active = (t.id===id));
  renderTabs();
  const active = tabs.find(t=>t.active);
  tabcontent.innerHTML='';
  if(active){
    const iframe = document.createElement('iframe');
    iframe.sandbox = 'allow-scripts allow-same-origin';
    iframe.src = active.url; iframe.referrerPolicy='no-referrer';
    tabcontent.appendChild(iframe);
  }
}

function closeTab(id){
  const idx = tabs.findIndex(t=>t.id===id);
  if(idx>=0){
    const removingActive = tabs[idx].active;
    tabs.splice(idx,1);
    if(removingActive && tabs.length>0){ setActive(tabs[tabs.length-1].id); }
    else if(tabs.length===0){ overlay.classList.add('hidden'); }
    renderTabs();
  }
}

function renderTabs(){
  tabsEl.innerHTML='';
  tabs.forEach(t => {
    const el = document.createElement('div');
    el.className='tab'+(t.active?' active':'');
    const img = document.createElement('img'); img.src=favicon(t.url); img.alt='';
    const label = document.createElement('span'); label.textContent = domain(t.url);
    const close = document.createElement('button'); close.className='close'; close.textContent='×';
    close.addEventListener('click', (e)=>{ e.stopPropagation(); closeTab(t.id); });
    el.addEventListener('click', ()=> setActive(t.id));
    el.append(img,label,close);
    tabsEl.appendChild(el);
  });
}

homeBtn.addEventListener('click', ()=>{ overlay.classList.add('hidden'); });

loadTiles();

import { describe, it, expect, beforeAll, afterAll } from 'vitest';
import { app } from '../src/server';
import http from 'node:http';
import request from 'supertest';

let server: http.Server;

beforeAll(async () => {
  server = app.listen(0);
});

afterAll(async () => {
  await new Promise<void>(resolve => server.close(()=>resolve()));
});

describe('portal server', () => {
  it('serves health', async () => {
    const res = await request(server).get('/health');
    expect(res.status).toBe(200);
    expect(res.body.ok).toBe(true);
  });
  it('serves index.html', async () => {
    const res = await request(server).get('/');
    expect(res.status).toBe(200);
    expect(res.text).toContain('<!doctype html>');
  });
  it('returns tiles (at least seeds)', async () => {
    const res = await request(server).get('/api/tiles');
    expect(res.status).toBe(200);
    const body = res.body as Array<any>;
    expect(Array.isArray(body)).toBe(true);
    expect(body.find(t => t.url && t.url.includes('starkitconsulting.com'))).toBeTruthy();
  });
});

