import express from 'express';
import fs from 'node:fs/promises';
import { existsSync } from 'node:fs';
import path from 'node:path';
import { chromium } from 'playwright';

const app = express();
app.use(express.json({ limit: '2mb' }));
const PORT = process.env.PORT ? Number(process.env.PORT) : 7070;
const RESULTS_DIR = process.env.RESULTS_DIR || '/workspace/webtest-results';

function ensureArray(a) { return Array.isArray(a) ? a : []; }

app.get('/health', (req, res) => {
  res.json({ ok: true, service: 'webtest-runner' });
});

app.post('/api/run', async (req, res) => {
  const { baseUrl, steps, label } = req.body || {};
  const runId = `${Date.now()}-${Math.random().toString(36).slice(2, 8)}`;
  const outDir = path.join(RESULTS_DIR, label ? `${label}-${runId}` : runId);
  await fs.mkdir(outDir, { recursive: true });

  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({ viewport: { width: 1366, height: 900 } });
  const page = await context.newPage();

  const results = [];
  let ok = true;

  async function doStep(step, idx) {
    const name = step.action || 'unknown';
    const entry = { index: idx, action: name, ok: true };
    try {
      switch (step.action) {
        case 'navigate': {
          const url = step.url || baseUrl;
          if (!url) throw new Error('navigate: url missing');
          await page.goto(url, { waitUntil: 'domcontentloaded', timeout: step.timeout ?? 30000 });
          break;
        }
        case 'waitForSelector': {
          await page.waitForSelector(step.selector, { timeout: step.timeout ?? 10000, state: step.state || 'visible' });
          break;
        }
        case 'click': {
          await page.click(step.selector, { timeout: step.timeout ?? 10000 });
          break;
        }
        case 'clickText': {
          const loc = page.locator(step.selector || '*', { hasText: step.text });
          await loc.first().click({ timeout: step.timeout ?? 10000 });
          break;
        }
        case 'expectVisible': {
          const loc = page.locator(step.selector);
          await loc.waitFor({ state: 'visible', timeout: step.timeout ?? 10000 });
          break;
        }
        case 'expectText': {
          const loc = page.locator(step.selector);
          const has = await loc.textContent();
          if (!has || !has.includes(step.includes)) throw new Error(`Text not found: ${step.includes}`);
          break;
        }
        case 'screenshot': {
          const file = step.path ? step.path : `step-${idx}.png`;
          const target = path.join(outDir, file);
          await page.screenshot({ path: target, fullPage: !!step.fullPage });
          entry.screenshot = target;
          break;
        }
        default:
          throw new Error(`Unknown action: ${step.action}`);
      }
    } catch (e) {
      entry.ok = false;
      entry.error = String(e?.message || e);
    }
    results.push(entry);
  }

  const plan = ensureArray(steps);
  for (let i = 0; i < plan.length; i++) {
    await doStep(plan[i], i);
    if (results[results.length - 1].ok === false) ok = false;
  }

  await browser.close();

  res.json({ ok, runId, outDir, results: results.map(r => ({ ...r, screenshot: r.screenshot ? r.screenshot.replace(RESULTS_DIR + '/', '') : undefined })) });
});

app.listen(PORT, () => {
  console.log(`webtest-runner listening on :${PORT}`);
});

