const { chromium } = require('playwright');
const fs = require('fs');
const path = require('path');
(async () => {
  const outRoot = '/workspace/webtest-results';
  const runId = 'portal-smoke-' + Date.now();
  const outDir = path.join(outRoot, runId);
  fs.mkdirSync(outDir, { recursive: true });
  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({ viewport: { width: 1366, height: 900 } });
  const page = await context.newPage();
  const baseUrl = 'http://192.168.50.191:8090';
  const results = [];
  async function step(name, fn){
    const entry = { name, ok: true };
    try { await fn(); } catch(e){ entry.ok=false; entry.error=String(e.message||e); }
    results.push(entry);
  }
  await step('navigate', async ()=>{ await page.goto(baseUrl, { waitUntil: 'domcontentloaded', timeout: 30000 }); });
  await step('wait slider', async ()=>{ await page.waitForSelector('.slider', { timeout: 10000, state: 'visible' }); });
  await step('shot home', async ()=>{ await page.screenshot({ path: path.join(outDir, 'home.png') }); });
  await step('expand', async ()=>{ await page.locator('.tile .chip', { hasText: 'EXPAND' }).first().click({ timeout: 10000 }); });
  await step('wait overlay', async ()=>{ await page.waitForSelector('.overlay', { state: 'visible', timeout: 10000 }); });
  await step('shot expanded', async ()=>{ await page.screenshot({ path: path.join(outDir, 'expanded.png') }); });
  await step('home', async ()=>{ await page.click('#homeBtn', { timeout: 10000 }); });
  await step('wait back', async ()=>{ await page.waitForSelector('.overlay.hidden', { state: 'attached', timeout: 10000 }); });
  await step('shot back', async ()=>{ await page.screenshot({ path: path.join(outDir, 'back.png') }); });
  await browser.close();
  console.log(JSON.stringify({ ok: results.every(r=>r.ok), outDir, results }, null, 2));
})().catch(e=>{ console.error(e); process.exit(1); });
